  ('prayer.verse', 'prayer', '"Cast all your anxiety on him because he cares for you."', '"Покладіть на Нього всю турботу свою, бо Він дбає про вас."', 'Auto-imported from site translations'),
  ('prayer.verseRef', 'prayer', '1 Peter 5:7', '1 Петра 5:7', 'Auto-imported from site translations'),
