  ('events.hero.description', 'events', 'Join us for worship nights, community gatherings, outreach events and more.', 'Служіння поклоніння, спільні зустрічі, особливі події — у Новій Надії завжди щось відбувається.', 'Auto-imported from site translations'),
  ('events.subtitle', 'events', 'Join us for our upcoming services, gatherings, and special events. Check our calendar to see what''s happening at Church of New Hope.', 'Приєднуйтесь до наших майбутніх служінь, зустрічей та особливих подій. Перегляньте наш календар.', 'Auto-imported from site translations'),
  ('give.title', 'give', 'Give', 'Пожертва', 'Auto-imported from site translations'),
  ('give.hero.eyebrow', 'give', 'Faithful giving changes lives', 'Щедрість', 'Auto-imported from site translations'),
  ('give.hero.script', 'give', 'Thank you', 'Дякуємо', 'Auto-imported from site translations'),
  ('give.hero.title', 'give', 'Give To Church of New Hope', 'Пожертвувати Новій Надії', 'Auto-imported from site translations'),
  ('give.hero.description', 'give', 'Every gift helps support the life and mission of our church through Sunday services, events, ministries, and missions efforts. Thank you for your generosity!', 'Кожна пожертва — велика чи мала — підтримує недільні служіння, дитяче та сімейне служіння та благовістя у Шарлотті.', 'Auto-imported from site translations'),
  ('give.subtitle', 'give', 'Support the ministry of Church of New Hope through your generous giving. Choose any of the options below.', 'Підтримайте служіння Церкви Нової Надії своєю щедрою пожертвою. Виберіть будь-який варіант нижче.', 'Auto-imported from site translations'),
  ('give.zelle.title', 'give', 'Zelle', 'Zelle', 'Auto-imported from site translations'),
  ('give.zelle.description', 'give', 'Send your gift directly to our Zelle account. Fast, secure, and no fees. Please add a note with your gift.', 'Надішліть пожертву безпосередньо на наш рахунок Zelle. Швидко, безпечно та без комісій. Будь ласка, додайте примітку.', 'Auto-imported from site translations'),
  ('give.zelle.phone', 'give', 'Phone:', 'Телефон:', 'Auto-imported from site translations'),
  ('give.zelle.note', 'give', 'Note:', 'Примітка:', 'Auto-imported from site translations'),
  ('give.zelle.noteValue', 'give', 'Tithe + Last Name', 'Tithe + Last Name', 'Auto-imported from site translations'),
  ('give.zelle.scanQR', 'give', 'Scan with your banking app', 'Відскануйте у банківському додатку', 'Auto-imported from site translations'),
  ('give.paypal.title', 'give', 'PayPal', 'PayPal', 'Auto-imported from site translations'),
  ('give.paypal.description', 'give', 'Donate securely through PayPal. Use your PayPal balance, a bank account, or any card.', 'Безпечні пожертви через PayPal. Використовуйте баланс PayPal, банківський рахунок або картку.', 'Auto-imported from site translations'),
  ('give.paypal.button', 'give', 'Give with PayPal', 'Пожертвувати через PayPal', 'Auto-imported from site translations'),
  ('give.paypal.secure', 'give', 'Secure donations processed by PayPal', 'Безпечні пожертви через PayPal', 'Auto-imported from site translations'),
  ('give.onlineGiving.title', 'give', 'Online giving', 'Онлайн пожертви', 'Auto-imported from site translations'),
  ('give.onlineGiving.description', 'give', 'Use our secure online giving platform powered by Square. Accepts all major credit cards and bank transfers.', 'Наша безпечна онлайн платформа на базі Square. Приймає всі основні картки та банківські перекази.', 'Auto-imported from site translations'),
  ('give.onlineGiving.button', 'give', 'Give online', 'Пожертвувати онлайн', 'Auto-imported from site translations'),
  ('give.thankYou', 'give', 'Thank you for your generous support of our ministry!', 'Дякуємо за вашу щедру підтримку!', 'Auto-imported from site translations'),
  ('give.taxDeductible', 'give', 'All donations are tax-deductible. You will receive a receipt for your records.', 'Усі пожертви не оподатковуються. Ви отримаєте квитанцію.', 'Auto-imported from site translations'),
  ('footer.churchName', 'footer', 'Church of New Hope', 'Церква Нової Надії', 'Auto-imported from site translations'),
