  ('footer.connect', 'footer', 'Connect', 'Слідкуйте', 'Auto-imported from site translations'),
  ('footer.connectText', 'footer', 'Follow us on social media for daily encouragement, announcements, and live worship.', 'Слідкуйте за нами у соцмережах для щоденного підбадьорення, оголошень та живого поклоніння.', 'Auto-imported from site translations'),
  ('footer.photos', 'footer', 'Photos by', 'Фото з', 'Auto-imported from site translations'),
  ('footer.copyright', 'footer', '© 2026 Church of New Hope. All rights reserved.', '© 2026 Церква Нової Надії. Усі права захищено.', 'Auto-imported from site translations'),
  ('forms.hero.eyebrow', 'forms', 'Get involved', 'Долучайтесь', 'Auto-imported from site translations'),
  ('forms.hero.title', 'forms', 'Forms & Requests', 'Форми та запити', 'Auto-imported from site translations'),
  ('forms.hero.description', 'forms', 'Everything you need in one place — connect with our church family, join a team, or submit a request to our staff.', 'Усе необхідне в одному місці — зв''яжіться з нашою церковною сім''єю, приєднайтесь до команди або надішліть запит нашому персоналу.', 'Auto-imported from site translations'),
  ('forms.openForm', 'forms', 'Open form', 'Відкрити форму', 'Auto-imported from site translations'),
  ('forms.groups.connect.eyebrow', 'forms', 'Take a next step', 'Зробіть наступний крок', 'Auto-imported from site translations'),
  ('forms.groups.connect.title', 'forms', 'Get Connected', 'Зв''яжіться з нами', 'Auto-imported from site translations'),
  ('forms.groups.requests.eyebrow', 'forms', 'For members & ministries', 'Для членів та служінь', 'Auto-imported from site translations'),
  ('forms.groups.requests.title', 'forms', 'Requests & Support', 'Запити та підтримка', 'Auto-imported from site translations'),
  ('forms.items.connectCard.title', 'forms', 'Connect Card', 'Картка знайомства', 'Auto-imported from site translations'),
  ('forms.items.connectCard.desc', 'forms', 'New here? Fill out our Connect Card so we can get to know you, answer any questions, and help you get connected at New Hope.', 'Вперше у нас? Заповніть Картку знайомства, щоб ми могли познайомитися з вами, відповісти на запитання та допомогти долучитися до Нової Надії.', 'Auto-imported from site translations'),
  ('forms.items.serveTeam.title', 'forms', 'Serve Team', 'Команда служіння', 'Auto-imported from site translations'),
  ('forms.items.serveTeam.desc', 'forms', 'Interested in serving? Complete this form to learn about volunteer opportunities and join a ministry team that matches your gifts and interests.', 'Хочете служити? Заповніть цю форму, щоб дізнатися про можливості волонтерства та приєднатися до команди служіння, що відповідає вашим дарам та інтересам.', 'Auto-imported from site translations'),
  ('forms.items.membership.title', 'forms', 'Membership Application', 'Заявка на членство', 'Auto-imported from site translations'),
  ('forms.items.membership.desc', 'forms', 'Ready to make New Hope your church home? Submit this application to begin the membership process and learn more about becoming a member.', 'Готові зробити Нову Надію своєю церквою? Подайте цю заявку, щоб розпочати процес членства та дізнатися більше про те, як стати членом.', 'Auto-imported from site translations'),
  ('forms.items.building.title', 'forms', 'Church Building Request', 'Запит на приміщення церкви', 'Auto-imported from site translations'),
  ('forms.items.building.desc', 'forms', 'Use this form to request the use of church facilities for meetings, events, classes, or special gatherings.', 'Використовуйте цю форму, щоб запросити приміщення церкви для зустрічей, подій, занять чи особливих зібрань.', 'Auto-imported from site translations'),
  ('forms.items.operator.title', 'forms', 'Operator Request', 'Запит оператору', 'Auto-imported from site translations'),
  ('forms.items.operator.desc', 'forms', 'Submit this form to request audio, video, livestream, presentation, or other technical support for your event or ministry activity.', 'Надішліть цю форму, щоб запросити аудіо, відео, трансляцію, презентацію чи іншу технічну підтримку для вашої події чи служіння.', 'Auto-imported from site translations'),
  ('forms.items.sermonSlides.title', 'forms', 'Sermon Slides Request', 'Запит на слайди проповіді', 'Auto-imported from site translations'),
  ('forms.items.sermonSlides.desc', 'forms', 'Use this form to submit sermon notes, scriptures, and presentation details needed to prepare slides for worship services.', 'Використовуйте цю форму, щоб надіслати нотатки проповіді, вірші та деталі презентації, потрібні для підготовки слайдів до богослужінь.', 'Auto-imported from site translations'),
  ('forms.items.graphic.title', 'forms', 'Graphic Request', 'Запит на графіку', 'Auto-imported from site translations'),
  ('forms.items.graphic.desc', 'forms', 'Need graphics for an event, ministry, or announcement? Submit this form to request flyers, social media graphics, presentation graphics, and other design projects.', 'Потрібна графіка для події, служіння чи оголошення? Надішліть цю форму, щоб замовити флаєри, графіку для соцмереж, презентації та інші дизайнерські проєкти.', 'Auto-imported from site translations'),
  ('forms.help.title', 'forms', 'Not sure which form you need?', 'Не знаєте, яка форма вам потрібна?', 'Auto-imported from site translations'),
  ('forms.help.body', 'forms', 'Reach out to us any time at info@churchofnewhope.org and we''ll point you in the right direction.', 'Звертайтесь до нас у будь-який час на info@churchofnewhope.org, і ми підкажемо вам правильний напрямок.', 'Auto-imported from site translations')
